func (s *ServerState) GetProjectByID(id string) (ProjectEntry, bool) {
	s.mu.RLock()
	defer s.mu.RUnlock()
	for _, p := range s.Projects {
		if p.ID == id {
			return p, true
		}
	}
	return ProjectEntry{}, false
}

// GetProjectByPath returns the project entry with the given path, if any.
